### Forms

In React, form elements like `<input>`, `<textarea>`, and `<select>` maintain their own internal state. Controlled components make React the single source of truth.

---

### Controlled Components

```jsx
function LoginForm() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log({ email, password });
  };

  return (
    <form onSubmit={handleSubmit}>
      <input
        type="email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
      />
      <input
        type="password"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
      />
      <button type="submit">Login</button>
    </form>
  );
}
```

### Select Dropdown

```jsx
<select value={selected} onChange={(e) => setSelected(e.target.value)}>
  <option value="">Choose</option>
  <option value="a">Option A</option>
  <option value="b">Option B</option>
</select>
```

### Uncontrolled Components (useRef)

```jsx
function UncontrolledForm() {
  const inputRef = useRef(null);
  const handleSubmit = (e) => {
    e.preventDefault();
    console.log(inputRef.current.value);
  };
  return (
    <form onSubmit={handleSubmit}>
      <input ref={inputRef} type="text" />
      <button type="submit">Submit</button>
    </form>
  );
}
```

| Approach | Description |
|----------|-------------|
| Controlled | React manages state via useState |
| Uncontrolled | DOM manages state, accessed via ref |

> **Key Point:** Controlled components are recommended for most cases as they provide instant validation, conditional submission, and enable React to control form state.

codeExample:
function NewsletterForm() {
  const [email, setEmail] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!email.includes('@')) {
      setError('Invalid email');
      return;
    }
    console.log('Subscribed:', email);
  };

  return (
    <form onSubmit={handleSubmit}>
      <input value={email} onChange={e => setEmail(e.target.value)} />
      {error && <p style={{ color: 'red' }}>{error}</p>}
      <button type="submit">Subscribe</button>
    </form>
  );
}
